{"script":"const fs = require('fs');
const path = require('path');

const workDir = '/Users/orion/Documents/大都会-申电云/需求单';

function searchFiles(dir, keyword) {
    const results = [];
    function walk(currentPath) {
        const entries = fs.readdirSync(currentPath, { withFileTypes: true });
        for (const entry of entries) {
            const fullPath = path.join(currentPath, entry.name);
            if (entry.isDirectory() && !entry.name.startsWith('.')) {
                walk(fullPath);
            } else if (entry.isFile() && !entry.name.startsWith('.')) {
                if (entry.name.toLowerCase().includes(keyword)) {
                    results.push({
                        所在目录: path.relative(workDir, currentPath) || '.',
                        文件名: entry.name,
                        完整路径: fullPath
                    });
                }
            }
        }
    }
    walk(dir);
    return results;
}

const results = searchFiles(workDir, '工作量');
console.log('=== 包含"工作量"的文件 ===');
results.forEach(r => {
    console.log(`\n📁 ${r.所在目录}`);
    console.log(`   📄 ${r.文件名}`);
    console.log(`   🔗 ${r.完整路径}`);
});

if (results.length === 0) {
    console.log('未找到任何包含"工作量"的文件。');
}"}
